import { useState, useEffect } from 'react';
import { Container, Card, Stack, Row, Text, Badge } from '@ggui-ai/design/primitives';

interface CurrentWeather {
  temperature: number;
  condition: 'sunny' | 'cloudy' | 'rainy' | 'snowy' | 'stormy' | 'windy';
  humidity: number;
  windSpeed: number;
}

interface ForecastDay {
  day: string;
  condition: 'sunny' | 'cloudy' | 'rainy' | 'snowy' | 'stormy' | 'windy';
  highTemp: number;
  lowTemp: number;
}

interface Props {
  location?: string;
  current?: CurrentWeather;
  forecast?: ForecastDay[];
}

const defaultCurrent: CurrentWeather = {
  temperature: 72,
  condition: 'sunny',
  humidity: 65,
  windSpeed: 12,
};

const defaultForecast: ForecastDay[] = [
  { day: 'Mon', condition: 'sunny', highTemp: 75, lowTemp: 62 },
  { day: 'Tue', condition: 'cloudy', highTemp: 70, lowTemp: 60 },
  { day: 'Wed', condition: 'rainy', highTemp: 65, lowTemp: 55 },
  { day: 'Thu', condition: 'cloudy', highTemp: 68, lowTemp: 58 },
  { day: 'Fri', condition: 'sunny', highTemp: 78, lowTemp: 64 },
];

// Weather icon mapping to emoji
const weatherIconMap: Record<string, string> = {
  sunny: '☀️',
  cloudy: '☁️',
  rainy: '🌧️',
  snowy: '❄️',
  stormy: '⛈️',
  windy: '💨',
};

// Weather condition variant mapping for badge colors
const weatherVariantMap: Record<string, 'success' | 'warning' | 'error' | 'info' | 'default'> = {
  sunny: 'success',
  cloudy: 'info',
  rainy: 'error',
  snowy: 'info',
  stormy: 'error',
  windy: 'warning',
};

export default function GeneratedComponent({
  location = 'San Francisco',
  current = defaultCurrent,
  forecast = defaultForecast,
}: Props) {
  const weatherIcon = weatherIconMap[current.condition] || '🌡️';
  const weatherVariant = weatherVariantMap[current.condition] || 'default';

  // Capitalize condition
  const conditionLabel = current.condition.charAt(0).toUpperCase() + current.condition.slice(1);

  return (
    <Container maxWidth="md">
      <Card shadow="md" padding="var(--ggui-spacing-6, 24px)">
        <Stack direction="vertical" gap={parseInt('var(--ggui-spacing-6, 24px)')}>
          {/* Header with location */}
          <div style={{
            paddingBottom: 'var(--ggui-spacing-4, 16px)',
            borderBottom: '2px solid var(--ggui-color-primary-200, #bae6fd)',
          }}>
            <Text variant="h2" color="var(--ggui-color-primary-900, #0c4a6e)">
              {location}
            </Text>
            <Text color="var(--ggui-color-neutral-500, #6b7280)" variant="body">
              Current Weather
            </Text>
          </div>

          {/* Current Weather Section */}
          <Stack direction="vertical" gap={parseInt('var(--ggui-spacing-4, 16px)')}>
            {/* Temperature and Condition */}
            <Row align="center" gap={parseInt('var(--ggui-spacing-4, 16px)')}>
              {/* Large temperature display */}
              <div style={{
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: 'var(--ggui-spacing-2, 8px)',
              }}>
                <div style={{
                  fontSize: 'var(--ggui-font-size-4xl, 36px)',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                  lineHeight: '1',
                }}>
                  {current.temperature}°
                </div>
                <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
                  Feels like {Math.round(current.temperature - 2)}°
                </Text>
              </div>

              {/* Weather icon and condition */}
              <Stack direction="vertical" gap={parseInt('var(--ggui-spacing-2, 8px)')}>
                <div style={{
                  fontSize: '3rem',
                  lineHeight: '1',
                }}>
                  {weatherIcon}
                </div>
                <Badge variant={weatherVariant}>
                  {conditionLabel}
                </Badge>
              </Stack>
            </Row>

            {/* Humidity and Wind Speed */}
            <Row gap={parseInt('var(--ggui-spacing-4, 16px)')}>
              {/* Humidity Card */}
              <div style={{
                flex: 1,
                padding: 'var(--ggui-spacing-4, 16px)',
                backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                display: 'flex',
                flexDirection: 'column',
                gap: 'var(--ggui-spacing-2, 8px)',
              }}>
                <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)" weight="semibold">
                  Humidity
                </Text>
                <div style={{
                  fontSize: 'var(--ggui-font-size-2xl, 24px)',
                  fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                }}>
                  {current.humidity}%
                </div>
              </div>

              {/* Wind Speed Card */}
              <div style={{
                flex: 1,
                padding: 'var(--ggui-spacing-4, 16px)',
                backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                display: 'flex',
                flexDirection: 'column',
                gap: 'var(--ggui-spacing-2, 8px)',
              }}>
                <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)" weight="semibold">
                  Wind Speed
                </Text>
                <div style={{
                  fontSize: 'var(--ggui-font-size-2xl, 24px)',
                  fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                }}>
                  {current.windSpeed} mph
                </div>
              </div>
            </Row>
          </Stack>

          {/* 5-Day Forecast */}
          <div style={{
            paddingTop: 'var(--ggui-spacing-4, 16px)',
            borderTop: '2px solid var(--ggui-color-primary-200, #bae6fd)',
          }}>
            <Text variant="h3" color="var(--ggui-color-primary-900, #0c4a6e)" style={{
              marginBottom: 'var(--ggui-spacing-4, 16px)',
            }}>
              5-Day Forecast
            </Text>

            <Row gap={parseInt('var(--ggui-spacing-2, 8px)')} wrap style={{
              justifyContent: 'space-between',
            }}>
              {forecast.map((day, idx) => {
                const dayIcon = weatherIconMap[day.condition] || '🌡️';
                const forecastKey = 'forecast_' + idx;

                return (
                  <div
                    key={forecastKey}
                    style={{
                      flex: '1 1 auto',
                      minWidth: '80px',
                      padding: 'var(--ggui-spacing-3, 12px)',
                      backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      border: '1px solid var(--ggui-color-primary-300, #7dd3fc)',
                      display: 'flex',
                      flexDirection: 'column',
                      alignItems: 'center',
                      gap: 'var(--ggui-spacing-2, 8px)',
                      textAlign: 'center',
                    }}
                  >
                    <Text variant="label" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">
                      {day.day}
                    </Text>
                    <div style={{
                      fontSize: '1.5rem',
                      lineHeight: '1',
                    }}>
                      {dayIcon}
                    </div>
                    <div style={{
                      display: 'flex',
                      gap: 'var(--ggui-spacing-1, 4px)',
                      alignItems: 'center',
                    }}>
                      <span style={{
                        fontSize: 'var(--ggui-font-size-sm, 14px)',
                        fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                        color: 'var(--ggui-color-primary-600, #0284c7)',
                      }}>
                        {day.highTemp}°
                      </span>
                      <span style={{
                        fontSize: 'var(--ggui-font-size-sm, 14px)',
                        color: 'var(--ggui-color-neutral-500, #6b7280)',
                      }}>
                        {day.lowTemp}°
                      </span>
                    </div>
                  </div>
                );
              })}
            </Row>
          </div>

          {/* Footer info */}
          <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" align="center">
            Last updated just now • Data refreshes every 30 minutes
          </Text>
        </Stack>
      </Card>
    </Container>
  );
}

import { useState } from 'react';
import { Container, Card, Stack, Row, Text, Input, TextArea, RadioGroup, Checkbox, Button, Divider, Icon } from '@ggui-ai/design/primitives';

interface RatingOption {
  value: string;
  label: string;
}

interface FeatureOption {
  id: string;
  label: string;
}

interface Props {
  ratingLabels?: RatingOption[];
  features?: FeatureOption[];
  onSubmit?: (data: SurveyData) => void;
}

interface SurveyData {
  name: string;
  email: string;
  satisfaction: string;
  interests: string[];
  comments: string;
}

interface FormErrors {
  name?: string;
  email?: string;
  satisfaction?: string;
}

const DEFAULT_RATING_LABELS: RatingOption[] = [
  { value: '1', label: 'Very Dissatisfied' },
  { value: '2', label: 'Dissatisfied' },
  { value: '3', label: 'Neutral' },
  { value: '4', label: 'Satisfied' },
  { value: '5', label: 'Very Satisfied' },
];

const DEFAULT_FEATURES: FeatureOption[] = [
  { id: 'feature1', label: 'User Interface' },
  { id: 'feature2', label: 'Performance' },
  { id: 'feature3', label: 'Customer Support' },
  { id: 'feature4', label: 'Documentation' },
  { id: 'feature5', label: 'Pricing' },
];

export default function GeneratedComponent({
  ratingLabels = DEFAULT_RATING_LABELS,
  features = DEFAULT_FEATURES,
  onSubmit,
}: Props) {
  const [step, setStep] = useState(0);
  const [formData, setFormData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: '',
    interests: [],
    comments: '',
  });
  const [errors, setErrors] = useState<FormErrors>({});

  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep = (currentStep: number): boolean => {
    const newErrors: FormErrors = {};

    if (currentStep === 0) {
      if (!formData.name.trim()) {
        newErrors.name = 'Name is required';
      }
      if (!formData.email.trim()) {
        newErrors.email = 'Email is required';
      } else if (!validateEmail(formData.email)) {
        newErrors.email = 'Please enter a valid email address';
      }
    } else if (currentStep === 1) {
      if (!formData.satisfaction) {
        newErrors.satisfaction = 'Please select a rating';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    if (validateStep(step)) {
      setStep(step + 1);
      setErrors({});
    }
  };

  const handleBack = () => {
    setStep(step - 1);
    setErrors({});
  };

  const handleNameChange = (value: string) => {
    setFormData(prev => ({ ...prev, name: value }));
    if (errors.name) {
      setErrors(prev => ({ ...prev, name: undefined }));
    }
  };

  const handleEmailChange = (value: string) => {
    setFormData(prev => ({ ...prev, email: value }));
    if (errors.email) {
      setErrors(prev => ({ ...prev, email: undefined }));
    }
  };

  const handleSatisfactionChange = (value: string) => {
    setFormData(prev => ({ ...prev, satisfaction: value }));
    if (errors.satisfaction) {
      setErrors(prev => ({ ...prev, satisfaction: undefined }));
    }
  };

  const handleInterestChange = (featureId: string) => {
    setFormData(prev => {
      const interests = prev.interests.includes(featureId)
        ? prev.interests.filter(id => id !== featureId)
        : [...prev.interests, featureId];
      return { ...prev, interests };
    });
  };

  const handleCommentsChange = (value: string) => {
    if (value.length <= 500) {
      setFormData(prev => ({ ...prev, comments: value }));
    }
  };

  const handleSubmit = () => {
    if (onSubmit) {
      onSubmit(formData);
    }
  };

  const progressPercentage = (step / 4) * 100;

  const renderStep = () => {
    switch (step) {
      case 0:
        return (
          <Stack direction="vertical" gap={20}>
            <div style={{ background: 'var(--ggui-color-primary-50, #f0f9ff)', padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', borderLeft: '4px solid var(--ggui-color-primary-500, #0ea5e9)' }}>
              <Text variant="label" style={{ color: 'var(--ggui-color-primary-900, #0c4a6e)' }}>Step 1 of 4: Personal Information</Text>
            </div>
            <Stack direction="vertical" gap={16}>
              <div>
                <Text as="label" htmlFor="name" variant="label" style={{ display: 'block', marginBottom: 'var(--ggui-spacing-2, 8px)', color: 'var(--ggui-color-neutral-900, #111827)', fontWeight: 'var(--ggui-font-weight-medium, 500)' }}>
                  Name <span style={{ color: 'var(--ggui-color-error-500, #ef4444)' }}>*</span>
                </Text>
                <Input
                  id="name"
                  label="Name"
                  placeholder="Enter your full name"
                  value={formData.name}
                  onChange={handleNameChange}
                  error={errors.name}
                  required
                />
              </div>
              <div>
                <Text as="label" htmlFor="email" variant="label" style={{ display: 'block', marginBottom: 'var(--ggui-spacing-2, 8px)', color: 'var(--ggui-color-neutral-900, #111827)', fontWeight: 'var(--ggui-font-weight-medium, 500)' }}>
                  Email <span style={{ color: 'var(--ggui-color-error-500, #ef4444)' }}>*</span>
                </Text>
                <Input
                  id="email"
                  label="Email"
                  type="email"
                  placeholder="you@example.com"
                  value={formData.email}
                  onChange={handleEmailChange}
                  error={errors.email}
                  required
                />
              </div>
            </Stack>
          </Stack>
        );
      case 1:
        return (
          <Stack direction="vertical" gap={20}>
            <div style={{ background: 'var(--ggui-color-primary-50, #f0f9ff)', padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', borderLeft: '4px solid var(--ggui-color-primary-500, #0ea5e9)' }}>
              <Text variant="label" style={{ color: 'var(--ggui-color-primary-900, #0c4a6e)' }}>Step 2 of 4: Satisfaction Rating</Text>
            </div>
            <RadioGroup
              label="How satisfied are you with our service?"
              value={formData.satisfaction}
              onChange={handleSatisfactionChange}
              options={ratingLabels.map(label => ({ value: label.value, label: label.label }))}
              direction="vertical"
              error={errors.satisfaction}
            />
          </Stack>
        );
      case 2:
        return (
          <Stack direction="vertical" gap={20}>
            <div style={{ background: 'var(--ggui-color-primary-50, #f0f9ff)', padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', borderLeft: '4px solid var(--ggui-color-primary-500, #0ea5e9)' }}>
              <Text variant="label" style={{ color: 'var(--ggui-color-primary-900, #0c4a6e)' }}>Step 3 of 4: Feature Interests</Text>
            </div>
            <div>
              <Text variant="label" style={{ display: 'block', marginBottom: 'var(--ggui-spacing-4, 16px)', color: 'var(--ggui-color-neutral-900, #111827)', fontWeight: 'var(--ggui-font-weight-medium, 500)' }}>
                Which features are you most interested in?
              </Text>
              <Stack direction="vertical" gap={12}>
                {features.map(feature => (
                  <Checkbox
                    key={feature.id}
                    label={feature.label}
                    checked={formData.interests.includes(feature.id)}
                    onChange={() => handleInterestChange(feature.id)}
                  />
                ))}
              </Stack>
            </div>
          </Stack>
        );
      case 3:
        return (
          <Stack direction="vertical" gap={20}>
            <div style={{ background: 'var(--ggui-color-primary-50, #f0f9ff)', padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', borderLeft: '4px solid var(--ggui-color-primary-500, #0ea5e9)' }}>
              <Text variant="label" style={{ color: 'var(--ggui-color-primary-900, #0c4a6e)' }}>Step 4 of 4: Additional Comments</Text>
            </div>
            <div>
              <Text as="label" htmlFor="comments" variant="label" style={{ display: 'block', marginBottom: 'var(--ggui-spacing-2, 8px)', color: 'var(--ggui-color-neutral-900, #111827)', fontWeight: 'var(--ggui-font-weight-medium, 500)' }}>
                Comments
              </Text>
              <TextArea
                id="comments"
                label="Comments"
                placeholder="Please share any additional feedback or comments (optional)"
                value={formData.comments}
                onChange={handleCommentsChange}
                maxLength={500}
                rows={5}
              />
              <div style={{ marginTop: 'var(--ggui-spacing-2, 8px)', fontSize: 'var(--ggui-font-size-xs, 12px)', color: 'var(--ggui-color-neutral-500, #6b7280)' }}>
                {formData.comments.length} / 500 characters
              </div>
            </div>
          </Stack>
        );
      case 4:
        return (
          <Stack direction="vertical" gap={20}>
            <div style={{ background: 'var(--ggui-color-success-500, #22c55e)', padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', color: 'white' }}>
              <Row gap={8} align="center">
                <Icon name="check" size={20} color="white" />
                <Text style={{ color: 'white', fontWeight: 'var(--ggui-font-weight-medium, 500)' }}>Review Your Answers</Text>
              </Row>
            </div>
            <Stack direction="vertical" gap={16}>
              <Card padding={16} border shadow="sm">
                <Stack direction="vertical" gap={12}>
                  <Text variant="label" style={{ color: 'var(--ggui-color-primary-600, #0284c7)', fontWeight: 'var(--ggui-font-weight-semibold, 600)' }}>Personal Information</Text>
                  <Row gap={8}>
                    <Text style={{ fontWeight: 'var(--ggui-font-weight-medium, 500)', minWidth: '100px' }}>Name:</Text>
                    <Text style={{ color: 'var(--ggui-color-neutral-600, #4b5563)' }}>{formData.name}</Text>
                  </Row>
                  <Row gap={8}>
                    <Text style={{ fontWeight: 'var(--ggui-font-weight-medium, 500)', minWidth: '100px' }}>Email:</Text>
                    <Text style={{ color: 'var(--ggui-color-neutral-600, #4b5563)' }}>{formData.email}</Text>
                  </Row>
                </Stack>
              </Card>

              <Card padding={16} border shadow="sm">
                <Stack direction="vertical" gap={12}>
                  <Text variant="label" style={{ color: 'var(--ggui-color-primary-600, #0284c7)', fontWeight: 'var(--ggui-font-weight-semibold, 600)' }}>Satisfaction Rating</Text>
                  <Row gap={8}>
                    <Text style={{ fontWeight: 'var(--ggui-font-weight-medium, 500)' }}>Rating:</Text>
                    <Text style={{ color: 'var(--ggui-color-neutral-600, #4b5563)' }}>
                      {ratingLabels.find(r => r.value === formData.satisfaction)?.label}
                    </Text>
                  </Row>
                </Stack>
              </Card>

              <Card padding={16} border shadow="sm">
                <Stack direction="vertical" gap={12}>
                  <Text variant="label" style={{ color: 'var(--ggui-color-primary-600, #0284c7)', fontWeight: 'var(--ggui-font-weight-semibold, 600)' }}>Feature Interests</Text>
                  {formData.interests.length > 0 ? (
                    <Stack direction="vertical" gap={8}>
                      {formData.interests.map(interestId => {
                        const feature = features.find(f => f.id === interestId);
                        return (
                          <Row key={interestId} gap={8} align="center">
                            <Icon name="check" size={16} color="var(--ggui-color-success-600, #16a34a)" />
                            <Text style={{ color: 'var(--ggui-color-neutral-600, #4b5563)' }}>{feature?.label}</Text>
                          </Row>
                        );
                      })}
                    </Stack>
                  ) : (
                    <Text style={{ color: 'var(--ggui-color-neutral-500, #6b7280)', fontStyle: 'italic' }}>No features selected</Text>
                  )}
                </Stack>
              </Card>

              <Card padding={16} border shadow="sm">
                <Stack direction="vertical" gap={12}>
                  <Text variant="label" style={{ color: 'var(--ggui-color-primary-600, #0284c7)', fontWeight: 'var(--ggui-font-weight-semibold, 600)' }}>Comments</Text>
                  <Text style={{ color: 'var(--ggui-color-neutral-600, #4b5563)', whiteSpace: 'pre-wrap' }}>
                    {formData.comments || <span style={{ fontStyle: 'italic', color: 'var(--ggui-color-neutral-500, #6b7280)' }}>No comments provided</span>}
                  </Text>
                </Stack>
              </Card>
            </Stack>
          </Stack>
        );
      default:
        return null;
    }
  };

  return (
    <Container maxWidth="md" padding={24}>
      <Card padding={24} shadow="md" border>
        <Stack direction="vertical" gap={24} role="form" aria-label="Customer feedback survey">
          <Stack direction="vertical" gap={12}>
            <Text variant="h2" style={{ color: 'var(--ggui-color-primary-900, #0c4a6e)' }}>Customer Feedback Survey</Text>
            <Text style={{ color: 'var(--ggui-color-neutral-600, #4b5563)' }}>We'd love to hear your feedback to help us improve</Text>
          </Stack>

          <div style={{ background: 'var(--ggui-color-neutral-100, #f3f4f6)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', padding: 'var(--ggui-spacing-4, 16px)', height: '6px', overflow: 'hidden' }} role="progressbar" aria-valuenow={progressPercentage} aria-valuemin={0} aria-valuemax={100}>
            <div style={{
              width: progressPercentage + '%',
              height: '100%',
              background: 'linear-gradient(to right, var(--ggui-color-primary-500, #0ea5e9), var(--ggui-color-primary-600, #0284c7))',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              transition: 'width 300ms ease-out'
            }} />
          </div>

          <Text align="center" variant="caption" style={{ color: 'var(--ggui-color-neutral-600, #4b5563)' }}>
            Step {step + 1} of 4
          </Text>

          <Divider margin={8} />

          {renderStep()}

          <Divider margin={8} />

          <Row justify="between" gap={12}>
            {step > 0 ? (
              <Button
                variant="outline"
                onClick={handleBack}
                aria-label="Go to previous step"
              >
                <Row gap={8} align="center">
                  <Icon name="chevron-left" size={16} />
                  Back
                </Row>
              </Button>
            ) : (
              <div />
            )}
            {step < 4 ? (
              <Button
                variant="primary"
                onClick={handleNext}
                aria-label="Go to next step"
              >
                <Row gap={8} align="center">
                  Next
                  <Icon name="chevron-right" size={16} />
                </Row>
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={handleSubmit}
                aria-label="Submit the survey"
              >
                <Row gap={8} align="center">
                  <Icon name="check" size={16} />
                  Submit Survey
                </Row>
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Button,
  Input,
  Select,
  Icon,
  Badge,
} from '@ggui-ai/design/primitives';

export interface Task {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
