const getBorderColor = (p: string): string =>
  p === 'high'
    ? 'var(--ggui-color-error-500, #ef4444)'
    : p === 'medium'
      ? 'var(--ggui-color-warning-500, #f59e0b)'
      : 'var(--ggui-color-success-500, #22c55e)';

function TaskCard({
  task,
  onEdit,
  onMove,
  onDelete,
  isEditing,
  editTitle,
  onEditChange,
  onSave,
}: any) {
  const left = getBorderColor(task.priority);
  return (
    <Card padding={12} shadow="sm" border style={{ borderLeft: left }}>
      <Stack direction="vertical" gap={8}>
        {isEditing ? (
          <Row gap={4}>
            <Input
              value={editTitle}
              onChange={onEditChange}
              placeholder="Task title"
            />
            <Button
              size="sm"
              variant="primary"
              onClick={() => onSave(task.id)}
              leftIcon={<Icon name="check" size={14} />}
            />
          </Row>
        ) : (
          <Row justify="between" align="start" gap={8} wrap>
            <Text
              weight="semibold"
              style={{ flex: 1, cursor: 'pointer', wordBreak: 'break-word' }}
              onDoubleClick={() => onEdit(task.id)}
            >
