export default function GeneratedComponent({
  initialTasks = DEFAULT_TASKS,
  onTaskUpdate,
}: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [editId, setEditId] = useState<string | null>(null);
  const [editVal, setEditVal] = useState('');
  const [addCol, setAddCol] = useState<string | null>(null);

  useEffect(() => {
    onTaskUpdate?.(tasks);
  }, [tasks, onTaskUpdate]);

  const total = tasks.length;
  const done = tasks.filter((t) => t.column === 'done').length;
  const pct = total > 0 ? Math.round((done / total) * 100) : 0;

  const handleEdit = (id: string) => {
    const t = tasks.find((x) => x.id === id);
    if (t) {
      setEditId(id);
      setEditVal(t.title);
    }
  };

  const handleSave = (id: string) => {
    if (editVal.trim()) {
      setTasks((p) =>
        p.map((t) => (t.id === id ? { ...t, title: editVal } : t))
      );
    }
    setEditId(null);
  };

  const handleAdd = (col: string, title: string, priority: string) => {
    const ts = new Date().getTime();
    setTasks((p) => [
      ...p,
      {
        id: 'task' + ts,
        title,
        priority: priority as 'low' | 'medium' | 'high',
        column: col as 'todo' | 'inprogress' | 'done',
      },
    ]);
    setAddCol(null);
  };

  const getByCols = (c: string) => tasks.filter((t) => t.column === c);

  return (
    <Container maxWidth="full" padding={0}>
      <Stack direction="vertical" gap={0}>
        <div
          style={{
            background: 'linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))',
            borderBottom: '2px solid var(--ggui-color-primary-200, #bae6fd)',
            padding: 'var(--ggui-spacing-6, 24px)',
          }}
        >
          <Stack direction="vertical" gap={16}>
            <div>
              <Text
                variant="h2"
                color="var(--ggui-color-primary-900, #0c4a6e)"
                weight="bold"
              >
                Task Board
              </Text>
              <Text color="var(--ggui-color-primary-700, #0369a1)">
                Manage your team workflow
              </Text>
            </div>
            <Row gap={24} wrap>
              <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                <div
                  style={{
                    width: 48,
                    height: 48,
                    borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                    background: 'var(--ggui-color-primary-200, #bae6fd)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                  }}
                >
                  <Text
                    variant="h3"
                    color="var(--ggui-color-primary-700, #0369a1)"
                    weight="bold"
                  >
                    {total}
                  </Text>
                </div>
                <div>
                  <Text
                    variant="label"
                    color="var(--ggui-color-primary-900, #0c4a6e)"
                    weight="semibold"
                  >
                    Total
                  </Text>
                  <Text
                    variant="caption"
                    color="var(--ggui-color-primary-700, #0369a1)"
                  >
                    All items
                  </Text>
                </div>
              </div>
              <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                <div
                  style={{
                    width: 48,
                    height: 48,
                    borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                    background: 'var(--ggui-color-success-500, #22c55e)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                  }}
                >
                  <Text variant="h3" color="white" weight="bold">
                    {done}
                  </Text>
                </div>
                <div>
                  <Text
                    variant="label"
                    color="var(--ggui-color-primary-900, #0c4a6e)"
                    weight="semibold"
                  >
                    Done
                  </Text>
                  <Text
                    variant="caption"
                    color="var(--ggui-color-primary-700, #0369a1)"
                  >
                    {pct}% complete
                  </Text>
                </div>
              </div>
            </Row>
          </Stack>
        </div>

        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))',
            gap: 'var(--ggui-spacing-6, 24px)',
            padding: 'var(--ggui-spacing-6, 24px)',
            background: 'var(--ggui-color-neutral-50, #f9fafb)',
            minHeight: '600px',
          }}
        >
          {COLUMNS.map((col) => {
            const colTasks = getByCols(col.id);
            const isAdd = addCol === col.id;

            return (
              <div
                key={col.id}
                style={{
                  display: 'flex',
                  flexDirection: 'column',
                  gap: 'var(--ggui-spacing-4, 16px)',
                }}
              >
                <div
                  style={{
                    background: 'var(--ggui-color-neutral-50, #f9fafb)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
