                  <Row justify="between" align="center" gap={8}>
                    <div>
                      <Text
                        variant="h3"
                        weight="semibold"
                        color="var(--ggui-color-primary-900, #0c4a6e)"
                      >
                        {col.label}
                      </Text>
                      <Badge variant="primary" size="sm">
                        {colTasks.length}
                      </Badge>
                    </div>
                  </Row>
                </div>

                <Stack direction="vertical" gap={12}>
                  {colTasks.map((task) => (
                    <TaskCard
                      key={task.id}
                      task={task}
                      isEditing={editId === task.id}
                      editTitle={editVal}
                      onEditChange={setEditVal}
                      onEdit={handleEdit}
                      onSave={handleSave}
                      onMove={(id: string, c: string) => {
                        setTasks((p) =>
                          p.map((t) =>
                            t.id === id
                              ? { ...t, column: c as Task['column'] }
                              : t
                          )
                        );
                      }}
                      onDelete={(id: string) => {
                        setTasks((p) => p.filter((t) => t.id !== id));
                      }}
                    />
                  ))}
                  {isAdd ? (
                    <AddForm
                      colId={col.id}
                      onAdd={handleAdd}
                      onCancel={() => setAddCol(null)}
                    />
                  ) : (
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => setAddCol(col.id)}
                      leftIcon={<Icon name="plus" size={16} />}
                      fullWidth
                    >
                      Add Task
                    </Button>
                  )}
                </Stack>
              </div>
            );
          })}
        </div>
      </Stack>
    </Container>
  );
}

