export default function GeneratedComponent({ elements = defaultElements, onElementSelect }: Props) {
  const { motionEnabled } = useMotion();
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return elements;
    const query = searchQuery.toLowerCase();
    return elements.filter(
      (el) =>
        el.name.toLowerCase().includes(query) ||
        el.symbol.toLowerCase().includes(query)
    );
  }, [searchQuery, elements]);

  const handleElementClick = (element: Element) => {
    setSelectedElement(element);
    onElementSelect?.(element);
  };

  const getElementColor = (category: Element['category']) => {
    return categoryConfig[category].color;
  };

  const elementsByPosition = useMemo(() => {
    const map = new Map<string, Element>();
    filteredElements.forEach((el) => {
      const key = el.period + '-' + el.group;
      map.set(key, el);
    });
    return map;
  }, [filteredElements]);

  const createPositionKey = (period: number, group: number): string => {
    return period + '-' + group;
  };

  const renderPeriodicTableGrid = () => {
    const rows = [];
    for (let period = 1; period <= 7; period++) {
      const rowCells = [];

      for (let group = 1; group <= 18; group++) {
        const key = createPositionKey(period, group);
        const element = elementsByPosition.get(key);

        // Skip positions that don't exist (lanthanides/actinides special placement)
        if (period === 6 && group >= 4 && group <= 17) continue;
        if (period === 7 && group >= 4 && group <= 17) continue;

        rowCells.push(
          <div
            key={key}
            style={{
              flex: '1 1 calc(5.56% - 8px)',
              minWidth: '40px',
              minHeight: '60px',
              margin: '4px',
              animation: motionEnabled ? animation.fadeIn : 'none',
            }}
          >
            {element ? (
              <button
                onClick={() => handleElementClick(element)}
                aria-label={'Element ' + element.symbol + ', ' + element.name + ', atomic number ' + element.atomicNumber}
                style={{
                  width: '100%',
                  height: '100%',
                  backgroundColor: getElementColor(element.category),
                  border: selectedElement?.atomicNumber === element.atomicNumber 
                    ? '3px solid var(--ggui-color-primary-700, #0369a1)' 
                    : '1px solid var(--ggui-color-neutral-300, #d1d5db)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  padding: 'var(--ggui-spacing-1, 4px)',
                  cursor: 'pointer',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  textAlign: 'center',
                  transition: 'all 200ms ease-out',
                  boxShadow: selectedElement?.atomicNumber === element.atomicNumber
                    ? '0 0 0 4px var(--ggui-color-primary-200, #bae6fd)'
                    : 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                  opacity: filteredElements.includes(element) ? 1 : 0.3,
                  pointerEvents: filteredElements.includes(element) ? 'auto' : 'none',
                  color: '#ffffff',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  fontSize: 'var(--ggui-font-size-sm, 14px)',
                  lineHeight: '1.2',
                }}
              >
                <span style={{ fontSize: 'var(--ggui-font-size-xs, 12px)', opacity: 0.9 }}>
                  {element.atomicNumber}
                </span>
                <span style={{ fontSize: 'var(--ggui-font-size-base, 16px)', fontWeight: 'var(--ggui-font-weight-bold, 700)' }}>
                  {element.symbol}
                </span>
              </button>
            ) : (
              <div />
            )}
          </div>
        );
      }

      rows.push(
        <div
          key={'period-' + period}
          style={{
            display: 'flex',
            flexWrap: 'wrap',
            marginBottom: 'var(--ggui-spacing-2, 8px)',
            animation: motionEnabled ? animation.slideInUp : 'none',
            animationDelay: (period * 30) + 'ms',
          }}
        >
          {rowCells}
        </div>
      );
    }
    return rows;
  };

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="full" padding={0}>
        <Stack direction="vertical" gap={24}>
          {/* Header */}
          <div
            style={{
              backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
              borderBottom: '2px solid var(--ggui-color-primary-200, #bae6fd)',
              padding: 'var(--ggui-spacing-6, 24px)',
            }}
          >
            <Stack direction="vertical" gap={12}>
              <Text variant="h1" color="var(--ggui-color-primary-900, #0c4a6e)">
                Interactive Periodic Table of Elements
              </Text>
              <Text color="var(--ggui-color-primary-700, #0369a1)">
                Explore the building blocks of matter. Click any element for details.
              </Text>
            </Stack>
          </div>

          {/* Search Input */}
          <div style={{ padding: '0 var(--ggui-spacing-6, 24px)' }}>
            <Text as="label" htmlFor="element-search">Search Elements</Text>
            <Input
              id="element-search"
              label="Search"
              placeholder="Search by element name or symbol (e.g., Gold, Au)"
              value={searchQuery}
              onChange={setSearchQuery}
            />
            {searchQuery && (
