import { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Button,
  Icon,
  Badge,
  Table,
  Tabs,
} from '@ggui-ai/design/primitives';

interface Review {
  id: string;
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface Specification {
  key: string;
  value: string;
}

interface Props {
  productId?: string;
  productName?: string;
  price?: number;
  currency?: string;
  rating?: number;
  reviewCount?: number;
  description?: string;
  specifications?: Specification[];
  reviews?: Review[];
  stock?: number;
  onAddToCart?: (data: { productId: string; quantity: number }) => void;
}

// Star rating display component
function StarRating({ value }: { value: number }) {
  return (
    <Row gap={2} align="center">
      {[...Array(5)].map((_, i) => (
        <span key={i} style={{ display: 'flex' }}>
          {i < Math.floor(value) ? (
            <Icon name="check" size={16} color="var(--ggui-color-warning-500, #f59e0b)" />
          ) : (
            <div
              style={{
                width: 16,
                height: 16,
                borderRadius: '50%',
                border: '1.5px solid var(--ggui-color-neutral-300, #d1d5db)',
              }}
            />
          )}
        </span>
      ))}
    </Row>
  );
}

// Get currency symbol safely
function getCurrencySymbol(currency: string): string {
  const symbols: { [key: string]: string } = {
    'USD': '$',
    'EUR': '€',
    'GBP': '£',
    'JPY': '¥',
    'INR': '₹',
  };
  return symbols[currency] || currency;
}

// Product header component
function ProductHeader({
  name,
  price,
  currency,
  rating,
  reviewCount,
  stock,
}: {
  name: string;
  price: number;
  currency: string;
  rating: number;
  reviewCount: number;
  stock: number;
}) {
  const isOutOfStock = stock === 0;
  const isLowStock = stock > 0 && stock <= 10;
  const symbol = getCurrencySymbol(currency);
  const formattedPrice = symbol + price.toFixed(2);

  return (
    <Stack direction="vertical" gap={24} style={{ flex: '1 1 auto', minWidth: '280px' }}>
      <Text variant="h2" color="var(--ggui-color-neutral-900, #111827)" weight="bold">
        {name}
      </Text>

      <Row gap={12} align="center">
        <StarRating value={rating} />
        <Text variant="body" color="var(--ggui-color-neutral-700, #374151)" weight="medium">
          {rating} ({reviewCount} reviews)
        </Text>
      </Row>

      <div style={{ borderBottom: '1px solid var(--ggui-color-neutral-200, #e5e7eb)', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
        <Text variant="h3" color="var(--ggui-color-primary-600, #0284c7)" weight="bold">
          {formattedPrice}
        </Text>
      </div>

      <Row gap={8} align="center">
        {isOutOfStock ? (
          <Badge variant="error" size="md">Out of Stock</Badge>
        ) : isLowStock ? (
          <Badge variant="warning" size="md">Low Stock ({stock} left)</Badge>
        ) : (
          <Badge variant="success" size="md">In Stock</Badge>
        )}
      </Row>
    </Stack>
  );
}

// Reviews list component
function ReviewsList({ reviews }: { reviews: Review[] }) {
  const formatDate = (dateString: string) => {
    return new Intl.DateTimeFormat('en-US', { year: 'numeric', month: 'short', day: 'numeric' }).format(new Date(dateString));
  };

  return (
    <Stack direction="vertical" gap={20}>
      {reviews.length > 0 ? (
        reviews.map((review) => (
          <Card key={review.id} padding="var(--ggui-spacing-4, 16px)" shadow="none" border>
            <Stack direction="vertical" gap={12}>
              <Row gap={16} justify="between" align="center">
                <Stack direction="vertical" gap={4}>
                  <Text variant="label" weight="semibold" color="var(--ggui-color-neutral-900, #111827)">
                    {review.author}
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                    {formatDate(review.date)}
                  </Text>
                </Stack>
                <Row gap={4} align="center">
                  <StarRating value={review.rating} />
                </Row>
              </Row>
              <Text variant="body" color="var(--ggui-color-neutral-700, #374151)">
                {review.text}
              </Text>
            </Stack>
          </Card>
        ))
      ) : (
        <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)">
          No reviews yet. Be the first to review!
        </Text>
      )}
    </Stack>
  );
}

// Quantity selector component
function QuantitySelector({
  value,
  onChange,
  max,
}: {
  value: number;
  onChange: (value: number) => void;
  max: number;
}) {
  const decrement = () => {
    if (value > 1) onChange(value - 1);
  };

  const increment = () => {
    if (value < max) onChange(value + 1);
  };

  return (
    <Stack direction="vertical" gap={8}>
      <Text as="label" htmlFor="qty" variant="label" color="var(--ggui-color-neutral-900, #111827)" weight="medium">
        Quantity
      </Text>
      <Row gap={0} align="center" style={{ border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', overflow: 'hidden' }}>
        <Button variant="ghost" size="sm" onClick={decrement} disabled={value <= 1} aria-label="Decrease quantity" style={{ borderRight: '1px solid var(--ggui-color-neutral-200, #e5e7eb)' }}>
          <Icon name="minus" size={16} />
        </Button>
        <input id="qty" type="number" value={value} onChange={(e) => { const v = parseInt(e.currentTarget.value, 10) || 1; if (v >= 1 && v <= max) onChange(v); }} min="1" max={max} style={{ width: '60px', textAlign: 'center', border: 'none', fontSize: 'var(--ggui-font-size-base, 16px)', fontWeight: 'var(--ggui-font-weight-medium, 500)', padding: 'var(--ggui-spacing-2, 8px)', backgroundColor: 'transparent' }} aria-label="Product quantity" />
        <Button variant="ghost" size="sm" onClick={increment} disabled={value >= max} aria-label="Increase quantity" style={{ borderLeft: '1px solid var(--ggui-color-neutral-200, #e5e7eb)' }}>
          <Icon name="plus" size={16} />
        </Button>
      </Row>
    </Stack>
  );
}

