import { useState, useEffect, useRef } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Button,
  Icon,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Message {
  id: string;
  sender: string;
  senderId: string;
  text: string;
  timestamp: string;
}

interface User {
  id: string;
  name: string;
}

interface Props {
  title?: string;
  participantCount?: number;
  currentUser: User;
  initialMessages?: Message[];
  onSend?: (data: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  participantCount = 2,
  currentUser,
  initialMessages = [],
  onSend,
}: Props) {
  const [messages, setMessages] = useState<Message[]>(initialMessages);
  const [inputValue, setInputValue] = useState('');
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, typingUsers]);

  // Listen for real-time data via ggui:agent-data event
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const { type, sender, senderId, text, timestamp } = customEvent.detail || {};

      if (type === 'message' && text && sender) {
        const msgTimestamp = timestamp || new Date().toISOString();
        const newMessage: Message = {
          id: String(Date.now()),
          sender: sender,
          senderId: senderId || 'unknown',
          text: text,
          timestamp: msgTimestamp,
        };
        setMessages((prev) => [...prev, newMessage]);
        // Clear typing indicator when message arrives
        setTypingUsers((prev) => {
          const updated = new Set(prev);
          updated.delete(senderId || sender);
          return updated;
        });
      } else if (type === 'typing' && sender) {
        setTypingUsers((prev) => new Set(prev).add(sender));
      }
    };

    const eventTarget = document as unknown as EventTarget;
    eventTarget.addEventListener('ggui:agent-data', handleAgentData);
    return () => {
      eventTarget.removeEventListener('ggui:agent-data', handleAgentData);
    };
  }, []);

  const handleSend = () => {
    if (!inputValue.trim()) return;

    const timestamp = new Date().toISOString();
    const newMessage: Message = {
      id: String(Date.now()),
      sender: currentUser.name,
      senderId: currentUser.id,
      text: inputValue,
      timestamp,
    };

    setMessages((prev) => [...prev, newMessage]);
    setInputValue('');

    onSend?.({ text: inputValue, timestamp });
  };

  const handleKeyPress = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const formatTime = (isoString: string) => {
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit',
        hour12: true,
      });
    } catch {
      return '';
    }
  };

  const isCurrentUser = (senderId: string) => senderId === currentUser.id;

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="full" padding={0} center={false}>
        <Card padding={0} shadow="md" border={false}>
          <Stack direction="vertical" gap={0} align="stretch">
            {/* Header */}
            <div
              style={{
                backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                borderBottom: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                padding: 'var(--ggui-spacing-4, 16px)',
              }}
            >
              <Row justify="between" align="center">
                <Stack direction="vertical" gap={4}>
                  <Text
                    variant="h3"
                    color="var(--ggui-color-primary-900, #0c4a6e)"
                    weight="semibold"
                  >
                    {title}
                  </Text>
                  <Text
                    variant="caption"
                    color="var(--ggui-color-primary-700, #0369a1)"
                  >
                    {participantCount} participant{participantCount !== 1 ? 's' : ''}
                  </Text>
                </Stack>
              </Row>
            </div>

            {/* Message List */}
            <div
              style={{
                flex: 1,
                overflowY: 'auto',
                padding: 'var(--ggui-spacing-4, 16px)',
                minHeight: '300px',
                maxHeight: '500px',
                display: 'flex',
                flexDirection: 'column',
                gap: 'var(--ggui-spacing-4, 16px)',
                backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
              }}
            >
              {messages.length === 0 ? (
                <div
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    height: '100%',
                    color: 'var(--ggui-color-neutral-500, #6b7280)',
                  }}
                >
                  <Text align="center">No messages yet. Start the conversation!</Text>
                </div>
              ) : (
                messages.map((msg, index) => {
                  const isOwn = isCurrentUser(msg.senderId);
                  const isLastMessage = index === messages.length - 1;
                  return (
                    <div
                      key={msg.id}
                      style={{
                        display: 'flex',
                        justifyContent: isOwn ? 'flex-end' : 'flex-start',
                        animation: motionEnabled && isLastMessage ? animation.slideInUp : 'none',
                      }}
                    >
                      <div
                        style={{
                          maxWidth: '70%',
                          display: 'flex',
                          flexDirection: 'column',
                          gap: 'var(--ggui-spacing-2, 8px)',
                          alignItems: isOwn ? 'flex-end' : 'flex-start',
                        }}
                      >
                        <Text
                          variant="caption"
                          color="var(--ggui-color-neutral-500, #6b7280)"
                          weight="medium"
                        >
                          {msg.sender}
                        </Text>
                        <div
                          style={{
                            backgroundColor: isOwn
                              ? 'var(--ggui-color-primary-600, #0284c7)'
                              : 'var(--ggui-color-neutral-200, #e5e7eb)',
                            color: isOwn
                              ? '#ffffff'
                              : 'var(--ggui-color-neutral-900, #111827)',
                            padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                            borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                            wordWrap: 'break-word',
                            whiteSpace: 'pre-wrap',
                          }}
                        >
                          <Text
                            variant="body"
                            color={
                              isOwn ? '#ffffff' : 'var(--ggui-color-neutral-900, #111827)'
                            }
                          >
                            {msg.text}
                          </Text>
                        </div>
                        <Text
                          variant="caption"
                          color="var(--ggui-color-neutral-500, #6b7280)"
                        >
                          {formatTime(msg.timestamp)}
                        </Text>
                      </div>
                    </div>
                  );
                })
              )}

              {/* Typing Indicator */}
              {typingUsers.size > 0 && (
                <div
                  style={{
                    display: 'flex',
                    justifyContent: 'flex-start',
                    animation: motionEnabled ? animation.slideInUp : 'none',
                  }}
                >
                  <div
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: 'var(--ggui-spacing-2, 8px)',
                      backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
                      padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                    }}
                  >
                    <Text variant="caption" color="var(--ggui-color-neutral-700, #374151)">
                      {Array.from(typingUsers).join(', ')} {typingUsers.size === 1 ? 'is' : 'are'} typing
                    </Text>
                    <span
                      style={{
                        display: 'flex',
                        gap: '4px',
                        alignItems: 'center',
                      }}
                    >
                      <span
                        style={{
                          width: '6px',
                          height: '6px',
                          borderRadius: '50%',
                          backgroundColor: 'var(--ggui-color-neutral-500, #6b7280)',
                          animation: motionEnabled
                            ? 'ggui-fadeIn 0.6s ease-in-out 0s infinite'
                            : 'none',
                        }}
                      />
                      <span
                        style={{
                          width: '6px',
                          height: '6px',
                          borderRadius: '50%',
                          backgroundColor: 'var(--ggui-color-neutral-500, #6b7280)',
                          animation: motionEnabled
                            ? 'ggui-fadeIn 0.6s ease-in-out 0.2s infinite'
                            : 'none',
                        }}
                      />
                      <span
                        style={{
                          width: '6px',
                          height: '6px',
                          borderRadius: '50%',
                          backgroundColor: 'var(--ggui-color-neutral-500, #6b7280)',
                          animation: motionEnabled
                            ? 'ggui-fadeIn 0.6s ease-in-out 0.4s infinite'
                            : 'none',
                        }}
                      />
                    </span>
                  </div>
                </div>
              )}

              <div ref={messagesEndRef} />
            </div>

            {/* Input Area */}
            <div
              style={{
                borderTop: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                padding: 'var(--ggui-spacing-4, 16px)',
                backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
              }}
            >
              <Stack direction="horizontal" gap={8} align="end">
                <div style={{ flex: 1 }}>
                  <Input
                    placeholder="Type a message..."
                    value={inputValue}
                    onChange={setInputValue}
                    onKeyPress={handleKeyPress}
                    aria-label="Message input"
                  />
                </div>
                <Button
                  variant="primary"
                  onClick={handleSend}
                  disabled={!inputValue.trim()}
                  rightIcon={<Icon name="chevron-right" size={16} />}
                  aria-label="Send message"
                  title={!inputValue.trim() ? 'Enter a message to send' : 'Send message'}
                >
                  Send
                </Button>
              </Stack>
            </div>
          </Stack>
        </Card>
      </Container>
    </>
  );
}
